export function getActivitiesForDestination(slug: string): CatalogActivity[] {
  return ACTIVITY_CATALOG.filter((a) => a.destination_slug === slug);
}

export function filterActivities(
  slug: string,
  interests: InterestTag[],
  timeOfDay?: string
): CatalogActivity[] {
  const interestSet = new Set(interests);
  return ACTIVITY_CATALOG.filter((a) => {
    if (a.destination_slug !== slug) return false;
    if (timeOfDay && a.best_time_of_day !== timeOfDay && a.best_time_of_day !== "anytime") return false;
    return true;
  }).sort((a, b) => {
    const aMatch = a.tags.some((t) => interestSet.has(t));
    const bMatch = b.tags.some((t) => interestSet.has(t));
    if (aMatch && !bMatch) return -1;
    if (!aMatch && bMatch) return 1;
    return 0;
  });
}
